+/**
+ * Pre-warm the semantic model (call during idle time)
+ */
+export async function warmupModel(options: SemanticOptions = {}): Promise<boolean> {
+  const pipeline = await loadTransformerPipeline(options);
+  return pipeline !== null;
+}
